// n8n Code node
// Работает с raw Responses API ответом OpenAI

function asObject(input) {
  if (Array.isArray(input)) return input[0] ?? null;
  return input ?? null;
}

function extractOpenAIOutputText(respRaw) {
  const resp = asObject(respRaw);
  if (!resp || typeof resp !== 'object') {
    return {
      ok: false,
      error: 'Response is empty or not an object',
      text: '',
      parsed: null,
      source: null,
    };
  }

  // 1) Самый удобный путь, если поле уже есть
  if (typeof resp.output_text === 'string' && resp.output_text.trim()) {
    const text = resp.output_text.trim();
    return {
      ok: true,
      error: null,
      text,
      parsed: tryParseJson(text),
      source: 'output_text',
    };
  }

  // 2) Фолбэк: ищем все message -> content -> output_text
  const chunks = [];
  const output = Array.isArray(resp.output) ? resp.output : [];

  for (const item of output) {
    if (!item || item.type !== 'message') continue;
    const content = Array.isArray(item.content) ? item.content : [];

    for (const part of content) {
      if (!part || part.type !== 'output_text') continue;
      if (typeof part.text === 'string' && part.text.trim()) {
        chunks.push(part.text);
      }
    }
  }

  if (chunks.length > 0) {
    const text = chunks.join('\n').trim();
    return {
      ok: true,
      error: null,
      text,
      parsed: tryParseJson(text),
      source: 'output[].message.content[].output_text.text',
    };
  }

  return {
    ok: false,
    error: 'No output text found in response.output_text or message content',
    text: '',
    parsed: null,
    source: null,
  };
}

function tryParseJson(text) {
  if (typeof text !== 'string') return null;
  const trimmed = text.trim();
  if (!trimmed) return null;

  try {
    return JSON.parse(trimmed);
  } catch {
    return null;
  }
}

const items = $input.all();

return items.map((item, index) => {
  const raw = item.json;
  const extracted = extractOpenAIOutputText(raw);

  return {
    json: {
      index,
      ok: extracted.ok,
      source: extracted.source,
      error: extracted.error,
      outputText: extracted.text,
      outputJson: extracted.parsed,
    }
  };
});
